import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.chrome.ChromeDriver;
import io.github.bonigarcia.wdm.WebDriverManager;
import java.time.Duration;

public class SeleniumTest {
    private WebDriver driver;

    public void setUp() {
        WebDriverManager.chromedriver().setup();
        driver = new ChromeDriver();
        driver.manage().timeouts().implicitlyWait(Duration.ofSeconds(10));
        driver.manage().window().maximize();
    }

    public void navigateToPage(String url) {
        driver.get(url);
    }

    public String getPageTitle() {
        return driver.getTitle();
    }

    public WebElement findElementById(String id) {
        return driver.findElement(By.id(id));
    }

    public void clickElement(WebElement element) {
        element.click();
    }

    public String getElementText(WebElement element) {
        return element.getText();
    }

    public void tearDown() {
        if (driver != null) {
            driver.quit();
        }
    }

    public static void main(String[] args) {
        SeleniumTest test = new SeleniumTest();
        try {
            test.setUp();
            test.navigateToPage("https://example.com");
            System.out.println("Page title: " + test.getPageTitle());

            WebElement heading = test.findElementById("example-heading");
            System.out.println("Heading text: " + test.getElementText(heading));
        } finally {
            test.tearDown();
        }
    }
}
